+func (h *GPUHandler) getCallerUser(c *fiber.Ctx) (*models.User, error) {
+	userID := middleware.GetUserID(c)
+	user, err := h.store.GetUser(userID)
+	if err != nil || user == nil {
+		return nil, fiber.NewError(fiber.StatusForbidden, "Unable to verify user")
